PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?novel ?novelLabel ?era ?eraLabel WHERE {
  wd:Q38337 wdt:P1476 ?novel ; wdt:P31 wd:Q7342 ; wdt:P2408 ?era .
  OPTIONAL {
    ?novel rdfs:label ?novelLabel
    FILTER(LANG(?novelLabel) = "en")
  }
  OPTIONAL {
    ?era rdfs:label ?eraLabel
    FILTER(LANG(?eraLabel) = "en")
  }
}

